// Emits 5 test messages tagged for the per-tag behaviour in the
// paired Queue Sample Consumer:
//   - 3 'happy' messages → succeed on first delivery
//   - 1 'transient_fail_once' → fails on delivery_count=1, succeeds on delivery_count=2 (exercises XAUTOCLAIM retry)
//   - 1 'poison' → fails on every delivery (exercises max_retries → DLQ)
// Streamed-name is taken from the webhook's optional `?stream=...` query
// param so the same producer can be pointed at multiple test streams without
// editing the template. Defaults to 'test-stream'.
const stream = $input.first().json.query?.stream || 'test-stream';
const payloads = [
  { tag: 'happy', idx: 1 },
  { tag: 'happy', idx: 2 },
  { tag: 'transient_fail_once', idx: 3 },
  { tag: 'happy', idx: 4 },
  { tag: 'poison', idx: 5 },
];
return payloads.map(p => ({ json: { stream, payload: p } }));

// Aggregate the message_ids returned by the per-item Queue Publish calls
// into a single summary item for the webhook response.
const items = $input.all();
return [{ json: {
  published_count: items.length,
  stream: items[0]?.json?.stream,
  message_ids: items.map(i => i.json.message_id),
} }];
